export const wordDocuments = {"jikeCompanyIntro":[{"type":"paragraph","text":"深圳市积科科技有限公司坐落于深圳，是一家专注于高分子环保助剂研发、生产、销售与技术服务一体化的现代化精细化工企业。公司深耕 PVC、CPVC 热稳定材料赛道多年，核心主营PVC 环保热稳定剂、CPVC 环保热稳定剂，同步自主生产赛克（三 (2 - 羟乙基) 异氰尿酸酯 / THEIC），构建起 “稳定剂成品 + 核心协效原料” 一体化产品体系，为橡塑、涂料、绝缘材料行业提供一站式环保解决方案。"},{"type":"paragraph","text":"积科科技配备标准化自动化生产车间与独立研发实验室，组建专业化工研发与应用技术团队，持续优化合成工艺与产品配方，严控原料甄选、生产加工、成品检测全流程品质，建立完善质量管控体系，保障产品批次稳定、供货充足。依托深圳区位优势与成熟供应链，公司兼顾国内市场深耕与外贸出口，可为客户提供定制化配方研发、现场工艺指导、样品测试等配套技术支持。"},{"type":"paragraph","text":"秉持 “科技赋能绿色橡塑，品质铸就长久合作” 的经营理念，积科科技以环保、高效、高性价比的助剂产品为核心竞争力，持续聚焦高分子新材料创新，致力成为 PVC/CPVC 环保热稳定剂与赛克领域值得信赖的源头生产服务商，携手下游产业共建低碳、安全、可持续的橡塑新材料生态。"},{"type":"paragraph","text":"深圳市积科科技有限公司"},{"type":"paragraph","text":"地址：深圳市坪山区坪山街道六联社区福安西一巷"},{"type":"paragraph","text":"联系人：丁丁"},{"type":"paragraph","text":"联系电话：13155217718"}],"jikeJk100":[{"type":"paragraph","text":"JK-100 环保热稳定剂产品说明书"},{"type":"paragraph","text":"文档版本：V1.0生效日期：2026 年 07 月 02 日"},{"type":"paragraph","text":"一、产品简介"},{"type":"paragraph","text":"JK-100是专为 PVC 高温加工研发的替代有机锡的有机复合稳定剂（不含有机锡），以多元有机配体、核心超支化化合物组合而成。环保合规，适PVC各类硬质制品的高温成型需求，兼具优异的热稳定性与加工适配性。"},{"type":"table","rows":[["检测项目","技术标准参数"],["外观","白色或微黄色均匀粉末"],["挥发份","≤1.2%"],["堆积密度","0.40～0.60g/cm³"],["动态润滑性能","内外润滑均衡，不析出、不粘模"]]},{"type":"paragraph","text":"二、理化技术指标"},{"type":"paragraph","text":"三、核心产品优势"},{"type":"paragraph","text":"1、全环保合规，适用多场景出口 / 市政工程"},{"type":"paragraph","text":"2、长效耐热稳定，低成本替代有机锡，添加量仅为有机锡的 1.5~2 倍；"},{"type":"paragraph","text":"3、提升熔体强度，成品力学性能优异"},{"type":"paragraph","text":"4、润滑平衡，成品外观光洁细腻"},{"type":"paragraph","text":"5、无析出、易加工，降低综合生产成本"},{"type":"paragraph","text":"四、适用范围"},{"type":"paragraph","text":"1、PVC-U 大口径管材：市政给水管、排水排污管、雨水管、电力穿线管、农田灌溉管；"},{"type":"paragraph","text":"2、中小型硬质 PVC 制品：挤出型材、塑料管件、挤出板材；"},{"type":"paragraph","text":"3 设备适配：单螺杆、双螺杆挤出设备通用，兼容低 / 高碳酸钙填充全系列硬质 PVC 配方。"},{"type":"paragraph","text":"五、使用操作方式"},{"type":"paragraph","text":"将本品与 PVC 树脂、碳酸钙、加工助剂、色母等原料一同投入高速混合机，常温高速搅拌均匀即可，无需额外预处理，适配行业标准化混料流程。配方优化建议：搭配少量管材专用抗氧剂、外润滑剂，可进一步提升管材耐候、抗老化性能，延长使用寿命。"},{"type":"paragraph","text":"六、包装、贮存与保质期"},{"type":"paragraph","text":"1、包装规格：25kg / 袋，加厚防潮复合纸袋，内置防水内膜，密封防尘、防破损；"},{"type":"paragraph","text":"2、贮存条件：存放于阴凉、干燥、通风室内仓库；远离热源、明火、高温设备，禁止阳光暴晒、雨淋潮湿，严禁与酸性、腐蚀性、氧化性物料混存；"},{"type":"paragraph","text":"3、保质期：原装密封状态保质期 12 个月；开封后及时扎紧袋口密封防潮，建议短期内用完，防止吸潮结块影响加工性能。"},{"type":"paragraph","text":"七、安全操作提示"},{"type":"paragraph","text":"1、本品属于环保粉末助剂，常规加工无刺激性；车间作业建议佩戴防尘口罩、防滑手套，避免长期大量吸入粉尘；"},{"type":"paragraph","text":"2、生产车间保持通风，定期清理设备、地面堆积粉尘；"},{"type":"paragraph","text":"3、不属于危险化学品，无易燃易爆风险，可常规公路、铁路运输装卸，禁止强力撞击、碾压破损包装；"},{"type":"paragraph","text":"4、应急处理：不慎接触皮肤、眼睛，立即用大量流动清水冲洗；若发生误食，请及时就医处理。"},{"type":"paragraph","text":"八、环保合规声明与免责说明"},{"type":"paragraph","text":"1、合规声明：产品通过 RoHS、REACH-SVHC、18 项 PAHs、PFOS/PFOA 全套环保检测，符合国内给排水管材卫生规范，满足各类工程、出口环保准入要求，可按需提供第三方检测报告。"},{"type":"paragraph","text":"2、免责说明：本说明书所有数据均为标准实验室测试值与通用生产指导，仅供客户配方、工艺调试参考。因客户设备型号、填料比例、挤出工艺、制品规格存在差异，正式量产前务必完成小试、中试验证；本公司不对未提前适配试验的非常规应用及成品质量承担相关责任。"}],"jikeJk619e":[{"type":"paragraph","text":"JK-619E大口径管材环保稳定剂（TDS）"},{"type":"paragraph","text":"文档版本：V1.0"},{"type":"paragraph","text":"生效日期：2026年06月09日"},{"type":"paragraph","text":"产品类型：PVC大口径给水管/排水管专用环保热稳定剂"},{"type":"paragraph","text":"一、产品概述"},{"type":"paragraph","text":"本产品为复合型环保钙锌热稳定剂，专为PVC大口径给水管、排水管、市政排污管、大口径穿线管等管材挤出成型工艺研发。采用有机稳定体系，耐高温高效助剂及平衡型润滑体系科学复配而成。产品无重金属、无硫污染、环保合规，具备超长热稳定时时间（不锌烧）、强熔体强度、无析出、高塑化稳定性等优势，完美适配大口径管材低速高扭矩、厚壁厚、冷却周期长的生产特性，可有效解决大口径管材加工过程中内壁发黄、熔体垂挂、塑化不良、端面发黑、管材脆裂等问题，保障大口径管材壁厚均匀、内外壁光滑、耐压性强、尺寸精度稳定，是大口径PVC管材生产的新一代优质环保专用助剂。"},{"type":"paragraph","text":"二、理化技术指标"},{"type":"table","rows":[["检测项目","技术指标","检测标准"],["外观","白色或微黄色均匀粉末","目视法"],["挥发份","≤1.2%","GB/T 11275"],["堆积密度","0.40～0.60g/cm³","GB/T 16913"],["动态润滑平衡","内外润滑均衡，无析出、不粘模","企业标准"]]},{"type":"paragraph","text":"三、核心产品特性"},{"type":"paragraph","text":"环保无毒合规：不含铅、镉、汞、铬等重金属有害物质，无硫污染、无异味，完全符合欧盟RoHS、REACH-SVHC、PAHs多环芳烃等国际环保标准，同时满足国标给水管道环保卫生要求，可用于家装、市政工程等高标准管材生产。"},{"type":"paragraph","text":"超长高温热稳定性：针对大口径管材壁厚较厚、挤出温度高、物料停留时间长、冷却速度慢的工艺特点，具备长效抗热分解能力，可有效杜绝管材内外壁发黄、端面焦黑、内层降解粉化等问题，适配大口径管材连续稳定量产。"},{"type":"paragraph","text":"管材力学性能优异：独特的配方体系不破坏PVC树脂分子结构，可提升管材熔体强度，有效避免大口径管材挤出时熔体垂挂、壁厚不均、管身变形等缺陷，保障管材耐压、抗冲击、耐弯折性能，符合管材国标力学检测标准。"},{"type":"paragraph","text":"润滑平衡、加工性极佳：精准匹配大口径管材挤出的高低速设备，内外润滑比例均衡，前期促塑化、后期保脱模，物料塑化均匀、熔体流动性稳定，管材内外壁光滑细腻、无气泡、无划痕、无麻点，大幅提升管材外观品质与成品合格率。"},{"type":"paragraph","text":"低析出、不粘模、易定型：高温加工无析出物，不会堵塞模具、口模、定型套，减少设备清理频次，适配大口径管材定型冷却工艺，加快定型速度，提升生产效率。"},{"type":"paragraph","text":"适配性广、性价比高：与PVC树脂、碳酸钙、增韧剂、色母等各类管材原料相容性极佳，不影响管材粘接、切割、焊接性能；添加量稳定，无需额外搭配大量润滑助剂，简化管材配方体系，有效降低生产综合成本。"},{"type":"paragraph","text":"四、适用范围"},{"type":"paragraph","text":"专用于各类大口径PVC-U管材生产，主要涵盖：大口径市政给水管、大口径排水排污管、大口径雨水管、大口径电力穿线管、大口径农田灌溉管等硬质、高填充PVC管材，适配各类大口径管材单螺杆、双螺杆挤出设备，兼容高钙粉填充管材配方体系。"},{"type":"paragraph","text":"五、推荐使用方法"},{"type":"paragraph","text":"推荐添加量：基于PVC树脂100份计量，常规添加量2.0～3.5PHR；高填充、大壁厚、低速生产工况可微适当提高用量，根据管材口径大小、填料比例、挤出温度灵活调整最佳用量。"},{"type":"paragraph","text":"使用方式：与PVC树脂、轻质/重质碳酸钙、加工助剂、色母等原料一同投入高速混合机，常温高速搅拌均匀即可，无需特殊预处理，混料工艺简单，适配管材标准化生产流程。"},{"type":"paragraph","text":"配方建议：适配大口径管材常规高填充配方，可搭配少量专用管材抗氧剂、外润滑剂，进一步提升管材耐候性、抗老化性，延长管材使用寿命，杜绝长期使用后脆化、开裂问题。"},{"type":"paragraph","text":"六、包装与贮存"},{"type":"paragraph","text":"包装规格：25kg/袋，采用加厚防潮复合纸袋包装，内置防水防潮内膜，密封防尘、防破损，适配批量仓储与运输。"},{"type":"paragraph","text":"贮存条件：储存于阴凉、干燥、通风的室内仓库，远离热源、明火、高温设备，避免阳光暴晒、雨淋、潮湿环境，严禁与酸性、腐蚀性、氧化性物质混存。"},{"type":"paragraph","text":"保质期：原装密封状态下，保质期12个月；开封后需及时扎紧袋口密封防潮，尽快用完，防止物料吸潮结块、影响使用效果。"},{"type":"paragraph","text":"七、安全与操作说明"},{"type":"paragraph","text":"本品为环保粉末助剂，常规管材加工操作无刺激性，车间作业时建议佩戴防尘口罩、防滑手套，避免长期大量吸入粉尘。"},{"type":"paragraph","text":"生产车间保持通风良好，定期清理设备及地面洒落物料，避免粉尘堆积，保障生产安全。"},{"type":"paragraph","text":"本品无易燃易爆风险，不属于危险化学品，可常规公路、铁路运输、装卸，禁止强力撞击、碾压、破损包装。"},{"type":"paragraph","text":"若不慎接触眼睛、皮肤，立即用大量流动清水冲洗；若不慎误食，请及时就医处理。"},{"type":"paragraph","text":"八、环保合规声明"},{"type":"paragraph","text":"本产品为环保无毒型管材专用助剂，严格符合RoHS指令、REACH法规、18项多环芳烃PAHs、PFOS/PFOA等国际环保检测标准，同时符合给排水管材相关卫生环保规范，无重金属、无有毒有害物质析出，可满足市政工程、家装管材等各类场景环保准入要求，可提供第三方权威检测报告。"},{"type":"paragraph","text":"九、免责说明"},{"type":"paragraph","text":"本说明书所列数据均为产品标准测试值与通用管材应用指导，仅供客户生产参考。因客户管材配方体系、设备型号、生产工艺、填充比例存在差异，建议客户正式量产前进行小试、中试适配，确认最佳添加量与生产工艺。本公司不对未经试验的非常规使用场景及结果承担相关责任。"}],"jikeJk318":[{"type":"paragraph","text":"PVC注塑管件专用钙锌稳定剂JK-318基本介绍"},{"type":"paragraph","text":"产品为白色或微黄粉状，具有初期着色好、塑化较快、润滑好、稳定时间长、生产开机时间长的优点。经SGS检测，满足ROHS2.0的要求。规格：25kg/袋应用领域：主要用于注塑管件、线盒等。"},{"type":"paragraph","text":"PVC注塑管件专用钙锌稳定剂JK-318性能特点"},{"type":"paragraph","text":"1. 初期着色好，热稳定性好，制品白度好。"},{"type":"paragraph","text":"2. 塑化时间较短，成型好。"},{"type":"paragraph","text":"3. 分散性好，制品光泽度高。"},{"type":"paragraph","text":"4. 加工性好，熔体强度高，制品强度高。"},{"type":"paragraph","text":"PVC注塑管件专用钙锌稳定剂JK-318技术参数"},{"type":"table","rows":[["检测项目","单位","技术指标"],["外观","白色或微黄粉状"],["挥发份","%","≦1"],["熔点","℃","≥80"],["密度","g/cm3","0.8-0.9"],["建议添加量（以PVC计）","%","4-6"]]},{"type":"paragraph","text":"PVC注塑管件专用钙锌稳定剂JK-318使用说明"},{"type":"paragraph","text":"应用领域：主要用于注塑管件、线盒等，可用于大管件。"},{"type":"paragraph","text":"PVC注塑管件专用钙锌稳定剂JK-318采购须知"},{"type":"paragraph","text":"● 本品为25Kg/袋"},{"type":"paragraph","text":"● PP编织外袋衬PE内袋，开袋后密封贮存，存放在阴凉干燥处，避免日晒雨淋，贮存期为12个月。"},{"type":"paragraph","text":"● 本产品说明书所包括之技术资料内容是通过检验和实际使用过程获得的。客户使用过程中具体使用量要根据配方、设备及工艺等条件综合考虑。"}],"jikeJk315":[{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315基本介绍"},{"type":"paragraph","text":"产品为白色或微黄色粉状，部分溶于乙醇或其他溶剂，不溶于水，遇强酸强碱分解，具有初期着色好、塑化较快、润滑好、稳定时间长、生产开机时间长的优点。经SGS检测，满足ROHS2.0的要求。"},{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315性能特点"},{"type":"paragraph","text":"1. 热稳定性好，开机周期长。"},{"type":"paragraph","text":"2. 分散性好，赋予PVC混合料良好的均匀塑化及高速熔融流动性。"},{"type":"paragraph","text":"3. 能够提高板材的剥离强度。"},{"type":"paragraph","text":"4. 加工性能好，使板材的机械性能好，收缩小，翘曲变形小。"},{"type":"paragraph","text":"5.可少加或不加ACR、CPE而达到地板的基本要求。"},{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315技术参数"},{"type":"table","rows":[["检测项目","单位","技术指标"],["外观","白色或微黄粉状"],["挥发份","%","≦1"],["初熔点","℃","≥80"],["密度","g/cm3","0.8-0.9"],["建议添加量（以PVC计）","%","6-8"]]},{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315使用说明"},{"type":"paragraph","text":"应用领域：主要用于SPC地板、大理石板、石塑墙板等。"},{"type":"paragraph","text":"SPC地板参考配方："},{"type":"paragraph","text":"PVC      100"},{"type":"paragraph","text":"CaCO3300-350"},{"type":"paragraph","text":"JK-315   7.5"},{"type":"paragraph","text":"回料100"},{"type":"paragraph","text":"G601.5-1.8"},{"type":"paragraph","text":"PE蜡1.5-1.8"},{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315采购须知"},{"type":"paragraph","text":"● 本品为25Kg/袋"},{"type":"paragraph","text":"● PP编织外袋衬PE内袋，开袋后密封贮存，存放在阴凉干燥处，避免日晒雨淋，贮存期为24个月。"},{"type":"paragraph","text":"● 因工艺条件及设备、环境不同，使用情况可能有差异，故而使用前请先试一手小料。"},{"type":"paragraph","text":"SPC地板专用钙锌稳定剂JK-315特别声明"},{"type":"paragraph","text":"●  本文所刊载的都是我们测定的可靠数据。不过，使用者必须自行决定产品的适用性。由于公司无从对所有状况与对象一概明了，所以不能保证产品在特定用法与用途上的正确性与适用性。阁下在使用产品之前，应先作彻底的验证。"}],"jikeAos508":[{"type":"paragraph","text":"AOS-508 压延有机环保稳定剂 技术数据表（TDS）"},{"type":"paragraph","text":"一、产品概述"},{"type":"paragraph","text":"AOS-508 为硬质 PVC 压延膜专用复合型环保热稳定剂，采用自主合成无金属纯有机化合物复配高锌稳定助剂制备而成。产品具备极低 VOC、低气味特性，不含游离苯酚，环保性能优异。"},{"type":"paragraph","text":"二、适用范围"},{"type":"paragraph","text":"不透明硬质 PVC 压延膜、卡基片材、印刷膜；"},{"type":"paragraph","text":"PVC 地板印刷层稳定加工。"},{"type":"paragraph","text":"三、理化技术指标"},{"type":"paragraph","text":"外观：白色均匀粉末 / 颗粒"},{"type":"paragraph","text":"加热减量（105℃/2h）：≤1.0%"},{"type":"paragraph","text":"细度：99% 通过 120 目筛"},{"type":"paragraph","text":"重金属（铅、镉、汞、六价铬）：均＜5ppm"},{"type":"paragraph","text":"四、推荐添加量"},{"type":"paragraph","text":"3～3.5 phr，可根据现场配方、工艺试验结果适当调整用量。"},{"type":"paragraph","text":"五、包装规格"},{"type":"paragraph","text":"25kg / 编织袋，亦可提供吨袋包装。"},{"type":"paragraph","text":"六、储存条件"},{"type":"paragraph","text":"储存环境温度控制在 15～30℃，本品吸湿性强，需严格防潮；"},{"type":"paragraph","text":"远离高温热源；"},{"type":"paragraph","text":"每次取用后及时密封包装，保持内部干燥；"},{"type":"paragraph","text":"保质期：自交货日期起 24 个月。"},{"type":"paragraph","text":"七、特别声明"},{"type":"paragraph","text":"本技术数据表内容均来源于实验室测试数据，仅作生产参考，不构成产品质量承诺。客户需结合自身配方、设备、工艺提前试样验证适配性。"}],"jikeAos10":[{"type":"paragraph","text":"AOS-10 有机稳定剂（CPVC专用）"},{"type":"paragraph","text":"产品型号：AOS-10"},{"type":"paragraph","text":"产品类型：CPVC专用有机稳定剂（非有机锡）"},{"type":"paragraph","text":"1. 产品概述"},{"type":"paragraph","text":"AOS-10 是专为 CPVC 高温加工研发的有机复合稳定剂（不含有机锡），以多元有机配体、核心超支化化合物组合而成。环保合规，适配CPVC各类硬质制品的高温成型需求，兼具优异的热稳定性与加工适配性。"},{"type":"paragraph","text":"2. 外观与形态"},{"type":"paragraph","text":"白色微粉状，无结块、无明显杂质，流动性良好，无刺激性异味。"},{"type":"paragraph","text":"3. 核心性能优势"},{"type":"paragraph","text":"高耐热稳定性：适配 CPVC 185–205℃ 高温加工，长期静态、动态热稳定性能优异，有效抑制CPVC高温降解，阻断HCl释放引发的链式反应，避免制品黄变、脆化。"},{"type":"paragraph","text":"低挥发、不析出：加工过程中挥发性极低，无明显异味，不易在制品表面析出，保障制品表面光洁度与性能稳定性。"},{"type":"paragraph","text":"高电绝缘性：绝缘性能优良，适配CPVC电力管、电缆护套管等高绝缘要求制品，保障使用安全性。"},{"type":"paragraph","text":"环保合规：无铅、无镉、无钡等有害重金属，不含有机锡，符合 RoHS、REACH、FDA 食品接触标准，适配环保型制品生产。"},{"type":"paragraph","text":"4. 适用范围"},{"type":"paragraph","text":"专为CPVC硬质制品设计，广泛应用于："},{"type":"paragraph","text":"CPVC电力管、工业化工管、给水管等各类管材制品；"},{"type":"paragraph","text":"CPVC型材、板材、注塑管件（弯头、接头等）；"},{"type":"paragraph","text":"食品接触级、卫生级CPVC制品（需配合食品级配方）；"},{"type":"paragraph","text":"CPVC高温挤出、注塑等成型工艺。"},{"type":"paragraph","text":"5. 推荐用量与加工条件"},{"type":"paragraph","text":"推荐用量：CPVC硬质制品 3.0–3.8 phr（以CPVC树脂100份为基准）；"},{"type":"paragraph","text":"加工温度：175–205℃（挤出/注塑），可根据制品类型适当调整；"},{"type":"paragraph","text":"混合建议：高速混合时温度控制在90–120℃，确保与CPVC树脂充分分散均匀，可搭配适量润滑剂优化加工性能。混合料需要冷却。"},{"type":"paragraph","text":"6. 包装规格"},{"type":"paragraph","text":"25 kg牛皮纸袋（内衬PE薄膜，密封防潮），可根据客户需求定制包装规格。"},{"type":"paragraph","text":"7. 储存条件"},{"type":"paragraph","text":"存放于阴凉、干燥、通风的库房，避免高温、暴晒、潮湿；密封保存，远离热源、明火及氧化剂；避免与强酸、强碱、腐蚀性物质混储；未开封状态下，保质期12个月。"},{"type":"paragraph","text":"8. 合规声明"},{"type":"paragraph","text":"本产品不含有机锡、无铅、无镉、无钡，符合 RoHS 2.0 (2011/65/EU)、REACH（无SVHC高关注物质）、FDA 21 CFR 177.1210（食品接触应用）及GB 9685-2016标准。"},{"type":"paragraph","text":"9. 责任声明"},{"type":"paragraph","text":"本TDS基于现有测试数据提供，仅供技术参考。用户需自行评估产品适用性，本司不承担因使用不当造成的损失。"}],"jikeTheic":[{"type":"paragraph","text":"商品名称：赛克"},{"type":"paragraph","text":"化学名称：三羟乙基异氰尿酸酯"},{"type":"paragraph","text":"分子式：C9H15N3O6"},{"type":"paragraph","text":"分子量：261.24"},{"type":"paragraph","text":"主要技术指标："},{"type":"paragraph","text":"外观：白色结晶性粉未或颗粒"},{"type":"paragraph","text":"熔点：133.5 - 137℃"},{"type":"paragraph","text":"羟值：640±10(KOHmg/g)"},{"type":"paragraph","text":"酸值：≤1.0(KOHmg/g)"},{"type":"paragraph","text":"PH：6.5-7.3"},{"type":"paragraph","text":"浊度：≤1.0NTU"},{"type":"paragraph","text":"干燥失重：≤0.3%"},{"type":"paragraph","text":"应用领域：用于PVC塑料稳定剂、耐热漆包线等产品的生产制造。"},{"type":"paragraph","text":"包装：25Kgs 500Kgs 800Kgs 1000Kgs,塑料编织袋内衬塑料袋。"}],"alphaCompanyIntro":[{"type":"paragraph","text":"阿尔法（深圳）环保新材料有限公司扎根深圳，是专注 PVC 制品配套环保功能性助剂研发、生产与技术服务的高新技术新材料企业，以 PVC 专用环保助剂为核心主营产品，聚焦单一功能性助剂材料赛道，为各类 PVC 制品制造企业提供高纯度、高适配、合规环保的原料解决方案。"},{"type":"paragraph","text":"成立至今，阿尔法始终坚持 “专一单品、绿色赋能橡塑产业” 的经营理念，聚焦 PVC 环保单一助剂细分赛道持续深耕，以纯粹、稳定、高性能的助剂单品为核心竞争力，持续研发低碳、低 VOC、高适配的新型环保助剂材料。未来公司将持续深耕单一功能助剂技术创新，打造 PVC 行业高可靠性专用助剂材料供应商，携手上下游共同构建安全、低碳、可持续的高分子新材料产业生态。"},{"type":"paragraph","text":"阿尔法（深圳）环保新材料有限公司"},{"type":"paragraph","text":"公司地址：深圳市雷柏中城生命科学园第3分园 A栋504"},{"type":"paragraph","text":"联系：徐军"},{"type":"paragraph","text":"电话：13609623668"}],"alphaDh273":[{"type":"paragraph","text":"DH-273锌烧抑制剂"},{"type":"paragraph","text":"简   介：产品属于多元醇酯类化合物，在PVC热稳定剂中用作抑制“锌烧”辅助助剂。"},{"type":"paragraph","text":"技术指标："},{"type":"paragraph","text":"外观：微黄色粉未"},{"type":"paragraph","text":"气味；无"},{"type":"paragraph","text":"比重；1.35g/l"},{"type":"paragraph","text":"酸值；≤2mg  KOH/g"},{"type":"paragraph","text":"熔点；150-170℃"},{"type":"paragraph","text":"加热减量：≤2%"},{"type":"paragraph","text":"产品特性："},{"type":"paragraph","text":"1. 精准抑制锌烧：独特羟基螫合构造，高效螫合锌离子，阻断催化降解链，从根源防止锌烧。"},{"type":"paragraph","text":"2、提升塑化均匀度：优异的相容性，增强PVC物料加工塑化效果，并有效提高产品的初期白度。"},{"type":"paragraph","text":"3、延长热稳定窗口：大幅提升钙锌体系加工中后期的热稳定性，保障工艺顺畅。"},{"type":"paragraph","text":"4、透明度突破：高度酯化合工艺，有效提升钙锌稳定剂在 PVC 中的透明度，制品更清澈透亮。在同类产品中，该产品是最接近有机锡的高透度。"},{"type":"paragraph","text":"5、抑制黄变析出：强力抑制锌烧导致的后期降解黄变，加工中不产生析出，确保外观纯净。"},{"type":"paragraph","text":"6、高端应用优选：特别适合高端透明/半透明PVC制品(包装膜、片材、医用品等)。"},{"type":"paragraph","text":"添 加 量：   建议在5-10%(厂家也可视自身实际调整加入量)"},{"type":"paragraph","text":"应用范围：   适用于软质、硬质PVC的粉体Ca-Zn、Ba-Zn配方，灵活适配。"},{"type":"paragraph","text":"产品储存：   置于阴凉通风处，产品开封如未用完，须保持紧密，防止受潮污染。"},{"type":"paragraph","text":"产品安全：   无气味、无硫化污染，参照MSDS中规定"},{"type":"paragraph","text":"包   装；    25Kg/包"},{"type":"paragraph","text":"推荐配方："},{"type":"paragraph","text":"硬脂酸锌： 35-40%"},{"type":"paragraph","text":"硬脂酸钙： 5-30%"},{"type":"paragraph","text":"DH-273:    5-10%"},{"type":"paragraph","text":"抗氧剂：   1-3%"},{"type":"paragraph","text":"DBM(B-二酮):   1-5%"},{"type":"paragraph","text":"内、外润滑：   5-10%"},{"type":"paragraph","text":"其它：     10-20%"},{"type":"paragraph","text":"责任声明："},{"type":"paragraph","text":"本说明书基于现有测试数据提供，仅供技术参考。用户需自行评估产品适用性，阿尔法（深圳）环保新材料有限公司不承担因使用不当造成的损失。"}],"alphaAef18":[{"type":"paragraph","text":"PVC加工稳定助剂 AEF-18"},{"type":"paragraph","text":"分子结构： AEF-18是钙的有机框架配位聚合物（MOFs），钙含量在20%±0.5，是高钙含量的化合物。结构图如下："},{"type":"paragraph","text":"应用范围：在工业应用中，AEF-18常用作橡胶、塑料材料的分散、降粘、稳定、润滑等功能性添加剂。"},{"type":"paragraph","text":"应用特点：在 PVC 制品中的应用特点体现如下："},{"type":"paragraph","text":"AEF-18在钙锌稳定剂中具有优良的初期白度，不像硬脂酸钙出现红黄底色；"},{"type":"paragraph","text":"AEF-18具有很好的分散性，降低体系的粘度，能同时提高流速和熔体流动性，缩短物料停留时间，可提高挤出产量和制品品质；"},{"type":"paragraph","text":"能配出非常纯白的白色稳定剂，没有黄红色相，不影响制品的发泡性能；"},{"type":"paragraph","text":"在 SPC 一包化辅料中，AEF-18 可减少 CPE、ACR 用量，且制品韧性不变；同时，可极大减小电流波动，使挤出性能稳定；"},{"type":"paragraph","text":"3）AEF-18 可降低挤出制品的残余应力，减小变形，提高尺寸稳定性；"},{"type":"paragraph","text":"4）在型材配方中，AEF-18 可避免黑丝纹和云纹的出现，同时控制制品缩痕的产生。"},{"type":"paragraph","text":"5）AEF-18 替代酯类润滑剂，可使硬质制品的热变形温度提高 1-5℃（依配方不同会有差异）"},{"type":"paragraph","text":"6）AEF-18 用于 PVC 软制品（如线缆）中，可减少鼓包、冒油等现象，提高外观品质；电线电缆泡水电阻率稳定；取代硬脂酸钙白度增白，减少析出，减少粘粒；亦可取代部分硬脂酸锌，提高塑化效果，白度保持。"},{"type":"paragraph","text":"7）建议在钙锌配方中替换部分的硬脂酸锌和硬脂酸钙，亦可作为润滑剂使用。"},{"type":"paragraph","text":"产品指标："},{"type":"table","rows":[["项 目","指 标"],["外 观","白色细粉"],["分解温度，℃","＞500"],["粒径 D50 ，μm","3~5"],["灰分，%","28.5±1.5"]]},{"type":"paragraph","text":"产品特点："},{"type":"paragraph","text":"1）无毒，可用于食品接触的材料中"},{"type":"paragraph","text":"2）分解温度大于 500℃,耐热性能优异"},{"type":"paragraph","text":"3）不迁移、不析出"},{"type":"paragraph","text":"安全性能："},{"type":"paragraph","text":"符合欧盟 RoHS 指令和 REACH 法规的要求。"},{"type":"paragraph","text":"贮存条件："},{"type":"paragraph","text":"本品具有极佳的贮存稳定性，存放于阴凉、通风、干燥的地方。"},{"type":"paragraph","text":"产品包装："},{"type":"paragraph","text":"复合袋包装，每件净重 25kg。"},{"type":"paragraph","text":"特别声明："},{"type":"paragraph","text":"本说明书是依据实验所得出的结论，不等同于对产品的承诺。"}],"alphaCcl601":[{"type":"paragraph","text":"电阻率稳定剂CCL-601"},{"type":"paragraph","text":"产品指标："},{"type":"table","rows":[["项 目","指 标"],["外 观","白色细粉"],["分解温度℃","＞500"],["粒径 D50 ，μm","3~5"],["灰分，%","26±1.5"]]},{"type":"paragraph","text":"产品特点："},{"type":"paragraph","text":"1）无毒，是一款有机钙盐，有效保持电线制品的水泡（含盐水）电阻率，基本不衰减"},{"type":"paragraph","text":"2）分解温度大于 500℃,耐热性能优异"},{"type":"paragraph","text":"3）与PVC相容性好，不迁移、不析出"},{"type":"paragraph","text":"应用特点："},{"type":"paragraph","text":"1.    在PVC生产中，有内润滑功能，不析出，无过量之弊"},{"type":"paragraph","text":"2.    在PVC生产中，可以提高流动性，使电线制品更加光亮"},{"type":"paragraph","text":"3.    建议添加量：0.5~1phr"},{"type":"paragraph","text":"4.    该产品具有稳定功效，提高稳定性，提升制品白度"},{"type":"paragraph","text":"产品包装:"},{"type":"paragraph","text":"纸塑袋包装，内衬PE膜防潮，25公斤一袋。40包一个卡板(托盘)，每个卡板(托盘)净重1000公"},{"type":"paragraph","text":"斤，外部由拉伸缠绕。"},{"type":"paragraph","text":"安全预防措施:"},{"type":"paragraph","text":"1.    一般非危险化工产品常规储存。"},{"type":"paragraph","text":"2.    CCL-601产品在使用常规的工业卫生做法处理时被视作无危害的,可用于食品接触。我们"},{"type":"paragraph","text":"可以提供材料安全性能数据以供参考。"},{"type":"paragraph","text":"特别声明："},{"type":"paragraph","text":"本说明书是依据实验所得出的结论，不等同于对产品的承诺。"}],"alphaAft180":[{"type":"paragraph","text":"粉体防团聚剂 AFT-180"},{"type":"paragraph","text":"一、产品简介"},{"type":"paragraph","text":"本品是聚羧酸盐类配位聚合物的粉体防团聚剂，通过化学锚固与空间位阻双重作用，在橡塑等高分子材料添加粉体加工场景下，实现颜填料的超细均匀稳定分散。"},{"type":"paragraph","text":"二、产品特点"},{"type":"paragraph","text":"超细分散：有效阻止颜填料粉体硬团聚形成，降低分散粒径，实现粉体在橡塑制品中"},{"type":"paragraph","text":"超细均匀分散。"},{"type":"paragraph","text":"长效稳定：避免粉体团聚引发门尼粘度升高与应力集中，保障橡塑成品及预分散母粒"},{"type":"paragraph","text":"的力学性能稳定。"},{"type":"paragraph","text":"环保耐温：无毒无味、不析出、无污染，可耐受高温加工。"},{"type":"paragraph","text":"三、用法用量"},{"type":"paragraph","text":"混炼工艺：在粉体物料加入前，先投入本品。"},{"type":"paragraph","text":"预混工艺：可与粉体物料同步预混。"},{"type":"paragraph","text":"推荐添加量：以粉体总重量计，建议从 0.3% 起，常规用量为 1.0%±0.5%。"},{"type":"paragraph","text":"四、技术指标"},{"type":"table","rows":[["项目","指标"],["外观","白色粉末"],["加热减量，%","≤1.5"],["灼烧减量，%",">70"],["细度（325 目通过率），%","全通"],["分解温度，℃","≥517"]]},{"type":"paragraph","text":"五、包装及储运"},{"type":"paragraph","text":"•   包装：内塑外编袋包装，净重 25kg。可将小包装于吨包内875KG/包。"},{"type":"paragraph","text":"•   储存：储存于阴凉、通风、干燥处。"},{"type":"paragraph","text":"•   运输：按一般无毒粉体材料运输。"}],"alphaTheic":[{"type":"paragraph","text":"商品名称：赛克"},{"type":"paragraph","text":"化学名称：三羟乙基异氰尿酸酯"},{"type":"paragraph","text":"分子式：C9H15N3O6"},{"type":"paragraph","text":"分子量：261.24"},{"type":"paragraph","text":"主要技术指标："},{"type":"paragraph","text":"外观：白色结晶性粉未或颗粒"},{"type":"paragraph","text":"熔点：133.5 - 137℃"},{"type":"paragraph","text":"羟值：640±10(KOHmg/g)"},{"type":"paragraph","text":"酸值：≤1.0(KOHmg/g)"},{"type":"paragraph","text":"PH：6.5-7.3"},{"type":"paragraph","text":"浊度：≤1.0NTU"},{"type":"paragraph","text":"干燥失重：≤0.3%"},{"type":"paragraph","text":"应用领域：用于PVC塑料稳定剂、耐热漆包线等产品的生产制造。"},{"type":"paragraph","text":"包装：25Kgs 500Kgs 800Kgs 1000Kgs,塑料编织袋内衬塑料袋。"}],"alphaAef477":[{"type":"paragraph","text":"高效辅助热稳定剂AEF-477"},{"type":"paragraph","text":"功能描述：钙/锌热稳定剂及有机锡热稳定剂专用高效辅助热稳定剂"},{"type":"paragraph","text":"应用特点：是一种无毒PVC共稳定剂，可抑制锌烧，它与钙/锌热稳定剂搭配使用，可以大幅度提高钙/锌热稳定剂的长期热稳定性；与有机锡稳定剂结合使用时可有效提高热稳定性，不影响维卡；无析出。"},{"type":"paragraph","text":"推荐用量： 0.1 - 0.6 phr（用户可根据自己的实验确定具体用量）"},{"type":"paragraph","text":"物化数据："},{"type":"table","rows":[["项目","单位","指标","测试方法"],["外观","==","白色粉末","目测"],["松密度","g/cc","0.3","APF00500"],["碱值","mgKOH/g","520～580",""],["比重","g/cm3","1.1～1.2",""]]},{"type":"paragraph","text":"注：所有数值均为典型值，而非质量标准。"},{"type":"paragraph","text":"包装规格：    25Kg/袋或吨袋"},{"type":"paragraph","text":"贮    存：存放在合适的区域：储存温度建议15-30℃，该产品对湿度很敏感。远离热源。使用后保持容器干燥并重新密封。最大建议的存储时间：交货之日起24个月。"}],"alphaAef32":[{"type":"paragraph","text":"硬脂酸根插层镁铝水滑石（AEF-32）技术数据表（TDS）"},{"type":"paragraph","text":"一、产品基础信息"},{"type":"paragraph","text":"1. 产品全称：硬脂酸根插层镁铝层状双金属氢氧化物（简称硬脂酸插层水滑石，St-LDH）2. 化学通式：Mg₃Al (OH)₈(C₁₈H₃₅O₂)・2H₂O3. 结构说明：层板为带正电镁铝复合氢氧化物，层间客体为完全插层硬脂酸根阴离子，区别于普通碳酸根包覆型水滑石；长烷基链撑开层板，XRD 特征层间距 3.2～3.5 nm。4. 相关 CAS 号：基体水滑石 11097-59-9；硬脂酸根 822-16-25. 适用范围：硬质 PVC 管材、门窗型材、硬质膜（片）材，适配无铅钙锌复合稳定体系；可用于双螺杆挤出、单螺杆挤出、注塑、压延等加工工艺。"},{"type":"paragraph","text":"二、产品核心优势（PVC 加工应用）"},{"type":"paragraph","text":"1. 双重热稳定作用：层间硬脂酸根快速捕捉 PVC 降解产生的 HCl，长碳链可置换分子链上不稳定烯丙基氯，制品初期白度远优于普通碳酸根型水滑石。2. 有效抑制锌烧：与钙锌稳定剂复配时，络合降解生成的氯化锌，减弱金属盐催化降解作用，长效热稳定时长提升 30%～50%。3. 与 PVC 相容性优异：烷基有机层降低粉体表面能，不易团聚，制品无白点、无晶点；自带内润滑效果，降低加工扭矩,改善熔体流动性，脱模性优异。4.通过插层改性的水滑石区别于普通水滑石的是具有优异的白度。5. 环保无毒无重金属：不含铅、镉，重金属含量符合 RoHS、食品接触材料相关标准，可用于环保无铅制品。6. 高温低析出：硬脂酸根通过离子键固定于层间，高温挤出不迁移、长期存放无析出现象。"},{"type":"paragraph","text":"三、出厂理化技术指标"},{"type":"table","rows":[["检测项目","指标要求","检测执行方法"],["外观","白色超细均匀粉末","目视法"],["氧化镁（MgO）质量分数","34.0%～37.0%","HG/T 3820、ICP 原子发射光谱"],["氧化铝（Al₂O₃）质量分数","13.0%～16.0%","HG/T 3820、ICP 原子发射光谱"],["层间硬脂酸根有机碳含量","18.0%～23.0%","元素分析仪 + TG 热重分析"],["105℃ 2h 挥发水分","≤0.50%","电热恒温烘箱失重法"],["500℃总灼烧失重","42%～48%","TG-DTA 同步热分析仪"],["325 目湿法筛余物","≤0.01%","湿法筛分试验"]]},{"type":"paragraph","text":"四、包装、储存与运输要求"},{"type":"paragraph","text":"1. 产品包装：25kg / 袋，内衬 PE 内膜，外层编织袋密封包装。2. 储存条件：存放于阴凉干燥仓库，环境温度≤30℃；严格防潮防雨，堆叠高度不超过 8 层，避免重压破袋吸潮。3. 产品保质期：密封干燥储存条件下有效期 12 个月；若物料受潮结块，使用前 105℃烘干 2 小时恢复性能。4. 运输说明：普通无机化工粉体，不属于危险化学品；运输过程避免暴晒、淋雨，轻装轻卸防止包装袋破损漏粉。"},{"type":"paragraph","text":"五、基础安全提示"},{"type":"paragraph","text":"1. 本品为超细粉体，操作过程易产生扬尘，作业时佩戴防尘口罩。2. 禁止口服，避免粉体溅入眼部；若接触皮肤 / 眼睛，使用大量流动清水冲洗。3. 废弃粉体、包装袋按一般工业固体废弃物处理，不属于有毒危险固废。"},{"type":"paragraph","text":"六、免责说明"},{"type":"paragraph","text":"本说明书所有数据均为标准实验室测试值与通用生产指导，仅供客户配方、工艺调试参考。本公司不对未提前适配试验的非常规应用及成品质量承担相关责任。"}],"alphaF37":[{"type":"paragraph","text":"F-37 高效复合离型润滑脱模助剂TDS"},{"type":"paragraph","text":"产品型号：F37 高效复合离型润滑脱模助剂"},{"type":"paragraph","text":"文件版本：V1.0     编制日期：2026-07-11"},{"type":"paragraph","text":"1. 产品概述"},{"type":"paragraph","text":"1.1 产品简介"},{"type":"paragraph","text":"F37 为高分子复合改性润滑离型助剂，采用特种有机金属活性组分搭配高分子改性聚烯烃载体，产品兼具界面隔离脱模与熔体均衡润滑双重效能，可有效提高塑化，改善加工过程粘模、模垢堆积、制品表面瑕疵等问题，适配各类硬质 PVC、CPVC 加工体系，与钙锌、稀土、有机锡等热稳定体系配伍性优异。"},{"type":"paragraph","text":"1.2 适用领域"},{"type":"paragraph","text":"CPVC 耐高温化工管件、冷热给水管道、UPVC给排水管材、门窗型材、注塑管件、板材、片材等挤出、注塑、压延等成型工艺。"},{"type":"paragraph","text":"2. 典型理化指标（25℃标准检测条件）"},{"type":"table","rows":[["检测项目","典型指标","检测标准/方法"],["外观","均匀白色微细粉体","目视观测"],["气味","轻微油脂本味，无刺激性异味","感官评定"],["熔融软化区间","110～125℃","熔点测定仪 DIN ISO 2176"],["酸值 (mgKOH/g)","≤10.0","GB/T 5530"],["水分含量","≤0.3%","105℃恒温失重法"],["高温挥发分 (150℃/1h)","≤0.5%","热失重烘箱测试"],["热稳定耐受温度","≥230℃","TG 热重分析检测"],["细度通过率（100 目标准筛）","≥98%","国标分样筛筛分法"]]},{"type":"paragraph","text":"3. 产品核心优势"},{"type":"paragraph","text":"3.1长效界面离型效果突出特有活性界面亲和结构，高温加工过程可定向迁移至熔体与金属模具接触面，形成连续均匀润滑隔离膜，大幅降低物料与模壁粘附力，减少粘模、拉丝、模头积碳积垢，延长设备清模周期，提升生产连续化效率。"},{"type":"paragraph","text":"3.2均衡复合润滑体系高分子改性载体优化粉体整体分散性能，平衡熔体内部摩擦阻力，改善塑化均匀度，兼顾内外润滑效果，不易出现局部润滑过剩、表面喷霜发白等不良现象。"},{"type":"paragraph","text":"3.3广谱配伍稳定性与各类硬质 PVC/CPVC 热稳定剂、酯类润滑剂、填料体系兼容，加工过程不易诱发制品变色，透明度稍差。"},{"type":"paragraph","text":"3.4低挥发低烟气加工友好整体热稳定性能优异，在 PVC、CPVC 常规加工温度区间挥发量低，生产过程油烟少，改善车间操作环境。"},{"type":"paragraph","text":"3.5优化制品表观品质减少成型后管材、型材表面麻点、划痕、凹凸瑕疵，显著提升成品表面光泽度与整体外观质感。"},{"type":"paragraph","text":"使用方法"},{"type":"paragraph","text":"将本品与 PVC/CPVC 树脂、热稳定剂、填料、配套润滑助剂共同投入高速混合设备，在 85～115℃区间充分混配均匀后，直接用于压延、挤出或注塑成型，无需单独预处理。"},{"type":"paragraph","text":"5. 包装、储存及保质周期"},{"type":"paragraph","text":"包装规格：25kg 内衬 PE 内膜编织袋封装。"},{"type":"paragraph","text":"储存条件：存放于阴凉干燥仓储环境，避光防潮，环境储存温度≤35℃，远离强酸、强氧化类物料"},{"type":"paragraph","text":"堆放要求：底部垫板离地存放，避免长期重压堆叠造成结块；轻微结块粉碎后不影响使用性能"},{"type":"paragraph","text":"保质期限：原厂密封状态下保质期 12 个月，开封后建议 3 个月内用完以保障使用效果。"},{"type":"paragraph","text":"6. 免责声明"},{"type":"paragraph","text":"本 TDS 所列参数均为标准实验室环境下典型参考数值，仅作为客户配方调试、工艺制定参考依据。因各厂家原料体系、生产设备、加工工艺存在差异，正式量产前务必开展小试验证最佳添加比例。本文档不构成产品质量担保，产品品质以双方购销合同约定标准为准。"}],"alphaZincBenzoate":[{"type":"paragraph","text":"苯甲酸锌说明书"},{"type":"paragraph","text":"基本信息"},{"type":"paragraph","text":"中文名称：苯甲酸锌（二苯甲酸锌）英文名称：Zinc Benzoate（Zinc Dibenzoate）"},{"type":"paragraph","text":"分子式：C₁₄H₁0O₄Zn  分子量：307.64  CAS号：553-72-0"},{"type":"paragraph","text":"外观：白色结晶粉末，无臭无味  溶解性：难溶于水，微溶于乙醇"},{"type":"paragraph","text":"锌含量：19.5%–20.5%（干基）"},{"type":"paragraph","text":"质量标准（企标）"},{"type":"table","rows":[["项目","指标"],["外观","白色粉末"],["粒径（目）","≥325"],["锌含量（%）","≥20.0"],["挥发度（105℃2h）（%）","≤1.0"]]},{"type":"paragraph","text":"主要用途"},{"type":"paragraph","text":"1. 食品工业：防腐剂（抑制霉菌/酵母菌）、酸化剂、锌营养强化剂；适用饮料、果酱、罐头、调味品等。"},{"type":"paragraph","text":"2. 塑料工业：PVC热稳定剂（提升透明/柔性PVC耐热耐候性）。"},{"type":"paragraph","text":"3. 涂料/纺织：油漆杀菌剂、纺织柔软剂/抗静电剂。"},{"type":"paragraph","text":"4. 医药/化妆品：防腐抑菌、锌补充剂原料。"},{"type":"paragraph","text":"用法用量"},{"type":"paragraph","text":"1. 食品添加：0.1–1.5 g/kg（以苯甲酸计）；果酱/蜜饯可用3%–5%水溶液浸渍后洗净。"},{"type":"paragraph","text":"2. PVC稳定剂：占配方1%–4%，与其他稳定剂复配。"},{"type":"paragraph","text":"3. 纺织印染：添加量0.5%–3%（对染液质量）。"},{"type":"paragraph","text":"包装规格"},{"type":"paragraph","text":"25 kg牛皮纸袋或编织袋（内衬PE薄膜，密封防潮），可根据客户需求定制包装规格。"},{"type":"paragraph","text":"储存条件"},{"type":"paragraph","text":"存放于阴凉、干燥、通风的库房，避免高温、暴晒、潮湿；密封保存，远离热源、明火及氧化剂；避免与强酸、强碱、腐蚀性物质混储；未开封状态下，保质期24个月。"},{"type":"paragraph","text":"合规声明"},{"type":"paragraph","text":"本产品不含有机锡、无铅、无镉、无钡，符合 RoHS 2.0 (2011/65/EU)、REACH（无SVHC高关注物质）、FDA 21 CFR 177.1210（食品接触应用）及GB 9685-2016标准。"},{"type":"paragraph","text":"责任声明"},{"type":"paragraph","text":"本TDS基于现有测试数据提供，仅供技术参考。用户需自行评估产品适用性，阿尔法（深圳）环保新材料有限公司不承担因使用不当造成的损失。"}]} as const satisfies Record<string, readonly DocumentBlock[]>
